const body = $input.first().json.body;

// Validate required fields
const required = ['campaign_name', 'audience_segment', 'campaign_type', 'from_name', 'from_email', 'reply_to'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Sanitise inputs — strip HTML from all string fields
function stripHtml(str) {
  return String(str).replace(/<[^>]*>/g, '').trim();
}

return [{
  json: {
    campaign_name: stripHtml(body.campaign_name),
    audience_segment: stripHtml(body.audience_segment),
    campaign_type: stripHtml(body.campaign_type), // welcome | nurture | re-engagement | promotional
    from_name: stripHtml(body.from_name),
    from_email: stripHtml(body.from_email),
    reply_to: stripHtml(body.reply_to),
    topic: stripHtml(body.topic || ''),
    offer: stripHtml(body.offer || ''),
    cta_url: stripHtml(body.cta_url || ''),
    delay_email_2_hours: parseInt(body.delay_email_2_hours || '48', 10),
    delay_email_3_hours: parseInt(body.delay_email_3_hours || '96', 10),
    created_at: new Date().toISOString()
  }
}];

