// Parse Ollama responses — extract JSON from the 'response' field
function parseOllamaResponse(node) {
  try {
    const raw = $node[node].json.response;
    // Extract JSON block (model may wrap it in markdown fences)
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) throw new Error(`No JSON found in ${node} response`);
    return JSON.parse(match[0]);
  } catch (e) {
    throw new Error(`Failed to parse ${node}: ${e.message}`);
  }
}

const email1 = parseOllamaResponse('Generate Email 1 Copy (Ollama)');
const email2 = parseOllamaResponse('Generate Email 2 Copy (Ollama)');
const email3 = parseOllamaResponse('Generate Email 3 Copy (Ollama)');

const campaign = $node['Validate and Sanitise Input'].json;

return [{
  json: {
    campaign_name: campaign.campaign_name,
    from_name: campaign.from_name,
    from_email: campaign.from_email,
    reply_to: campaign.reply_to,
    delay_email_2_hours: campaign.delay_email_2_hours,
    delay_email_3_hours: campaign.delay_email_3_hours,
    email_1: email1,
    email_2: email2,
    email_3: email3,
    preview_text: `REVIEW REQUIRED — Campaign: ${campaign.campaign_name}\n\nEmail 1 Subject: ${email1.subject}\nEmail 2 Subject: ${email2.subject}\nEmail 3 Subject: ${email3.subject}`
  }
}];

